  1	import * as React from 'react';
  2	import { DrawerHead, Status, useCustomTranslation } from '@odf/shared';
  3	import { ResourceStatus } from '@openshift-console/dynamic-plugin-sdk';
  4	import { observer } from 'mobx-react-lite';
  5	import {
  6	  Drawer,
  7	  DrawerActions,
  8	  DrawerCloseButton,
  9	  DrawerContent,
 10	  DrawerContentBody,
 11	  DrawerPanelContent,
 12	  Flex,
 13	  FlexItem,
 14	  Title,
 15	} from '@patternfly/react-core';
 16	import { uploadStore } from './store';
 17	import UploadStatusList from './upload-status';
 18	import { getTotalTimeElapsed } from './utils';
 19	
 20	type PanelContentProps = {
 21	  onClose: () => void;
 22	  completionTime: number;
 23	};
 24	
 25	const PanelContent: React.FC<PanelContentProps> = observer(
 26	  ({ onClose, completionTime }) => {
 27	    const { t } = useCustomTranslation();
 28	
 29	    const uploadedFiles = uploadStore.getCompletedFilesCount;
 30	    const failedFiles = uploadStore.getFailedAndCancelledFilesCount;
 31	    const totalFiles = uploadStore.getTotalFilesCount;
 32	    const uploadSpeed = uploadStore.getUploadSpeed;
 33	    const totalRemaining = uploadStore.getTotalRemainingFilesAndSize;
 34	    const timeRemaining = uploadStore.getTotalTimeRemaning;
 35	
 36	    const uploadProgress = uploadStore.getAll;
 37	    const totalTimeElapsed = getTotalTimeElapsed(
 38	      uploadProgress,
 39	      completionTime
 40	    );
 41	    const isComplete = uploadedFiles + failedFiles === totalFiles;
 42	
 43	    return (
 44	      <DrawerPanelContent
 45	        isResizable
 46	        defaultSize="500px"
 47	        minSize="150px"
 48	        maxSize="unset"
 49	        height="unset"
 50	      >
 51	        <DrawerHead>
 52	          <Flex direction={{ default: 'column' }}>
 53	            <FlexItem>
 54	              <Title headingLevel="h3">{t('Uploads')}</Title>
 55	            </FlexItem>
 56	            <FlexItem>
 57	              <Title headingLevel="h4">
 58	                <span>
 59	                  {t('{{uploadedFiles}} of {{totalFiles}} files uploaded', {
 60	                    uploadedFiles,
 61	                    totalFiles,
 62	                  })}
 63	                  &nbsp;
 64	                  {isComplete ? (
 65	                    <ResourceStatus>
 66	                      <Status status={t('Complete')} title={t('Completed')} />
 67	                    </ResourceStatus>
 68	                  ) : (
 69	                    <ResourceStatus>
 70	                      <Status status={t('Uploading')} title={t('Ongoing')} />
 71	                    </ResourceStatus>
 72	                  )}
 73	                </span>
 74	              </Title>
 75	            </FlexItem>
 76	            {isComplete ? (
 77	              <>
 78	                <FlexItem>
 79	                  {t('Succeeded: {{uploadedFiles}}', { uploadedFiles })}
 80	                </FlexItem>
 81	                <FlexItem>
 82	                  {t('Failed files: {{failedFiles}}', {
 83	                    failedFiles: totalFiles - uploadedFiles,
 84	                  })}
 85	                </FlexItem>
 86	                <FlexItem>
 87	                  {t('Completion time: {{totalTimeElapsed}}', {
 88	                    totalTimeElapsed,
 89	                  })}
 90	                </FlexItem>
 91	              </>
 92	            ) : (
 93	              <>
 94	                <FlexItem>
 95	                  {t('Total Remaining: {{totalRemaining}}', { totalRemaining })}
 96	                </FlexItem>
 97	                <FlexItem>
 98	                  {t('Estimated time remaining: {{timeRemaining}}', {
 99	                    timeRemaining,
100	                  })}
101	                </FlexItem>
102	                <FlexItem>
103	                  {t('Transfer rate: {{uploadSpeed}}', { uploadSpeed })}
104	                </FlexItem>
105	              </>
106	            )}
107	          </Flex>
108	          <DrawerActions>
109	            <DrawerCloseButton onClick={onClose} />
110	          </DrawerActions>
111	        </DrawerHead>
112	        <DrawerContentBody>
113	          <UploadStatusList />
114	        </DrawerContentBody>
115	      </DrawerPanelContent>
116	    );
117	  }
118	);
119	
120	export type UploadSidebarProps = {
121	  isExpanded: boolean;
122	  closeSidebar: () => void;
123	  mainContent: React.ReactNode;
124	  completionTime: number;
125	};
126	
127	export const UploadSidebar: React.FC<UploadSidebarProps> = ({
128	  isExpanded,
129	  closeSidebar,
130	  mainContent: drawerContentBody,
131	  completionTime,
132	}) => {
133	  return (
134	    <Drawer isExpanded={isExpanded} position="right">
135	      <DrawerContent
136	        panelContent={
137	          <PanelContent
138	            onClose={closeSidebar}
139	            completionTime={completionTime}
140	          />
141	        }
142	      >
143	        <DrawerContentBody>{drawerContentBody}</DrawerContentBody>
144	      </DrawerContent>
145	    </Drawer>
146	  );
147	};

